protected boolean checkTrans(JournalTransData _journalTransData)
{

    Boolean isValid = next checkTrans(_journalTransData);

    if(ETGACFParameters::find().EnablefinancialdimensionVertical == NoYes::Yes)
    {
        if(isvalid == false)
        {
            InventJournalTrans  inventJournalTrans  = _journalTransData.journalTrans();
            if(inventJournalTrans.inventJournalTable().inventJournalName().ETGTransferJournalFDChange)
            {
                isValid = true;
            }
        }
    }
    return isValid;

}
